const items = $input.all();
const allFeedback = [];

// App reviews
try {
  const appData = items[0]?.json;
  const entries = appData?.feed?.entry || [];
  entries.slice(0,50).forEach(e => {
    const text = e?.content?.label || '';
    if (text.length > 10) allFeedback.push({ source:'app_review', text: text.slice(0,200), score: parseInt(e?.['im:rating']?.label || 3), date: e?.updated?.label });
  });
} catch(e) {}

// NPS verbatims
try {
  const npsItems = items[1]?.json;
  (Array.isArray(npsItems) ? npsItems : []).forEach(r => {
    if (r.comment) allFeedback.push({ source:'nps', text: r.comment.slice(0,200), score: parseInt(r.score), date: r.created_at });
  });
} catch(e) {}

// Support tickets
try {
  const tickets = items.filter(i => i.json.properties?.subject);
  tickets.forEach(t => {
    const text = (t.json.properties?.subject?.value || '') + ' ' + (t.json.properties?.content?.value || '');
    allFeedback.push({ source:'support', text: text.slice(0,200), score: 2, date: t.json.createdAt });
  });
} catch(e) {}

// Deduplicate by text hash
const seen = new Set();
const deduped = allFeedback.filter(f => {
  const key = f.text.toLowerCase().replace(/\s+/g,' ').slice(0,50);
  if (seen.has(key)) return false;
  seen.add(key); return true;
});

return [{ json: { feedback: deduped, total: deduped.length } }];

const ai = JSON.parse($json.message.content);
const feedback = $('Normalise & Dedupe').first().json.feedback;
const classified = Array.isArray(ai) ? ai : Object.values(ai)[0];

const themes = {};
classified.forEach(item => {
  const f = feedback[item.index];
  if (!f) return;
  const t = item.theme;
  if (!themes[t]) themes[t] = { theme: t, count: 0, sentiment_sum: 0, quotes: [] };
  themes[t].count++;
  themes[t].sentiment_sum += item.sentiment;
  if (themes[t].quotes.length < 3) themes[t].quotes.push(f.text.slice(0,100));
});

const ranked = Object.values(themes)
  .map(t => ({ ...t, avg_sentiment: (t.sentiment_sum/t.count).toFixed(1), impact_score: t.count * (6 - t.sentiment_sum/t.count) }))
  .sort((a,b) => b.impact_score - a.impact_score);

return [{ json: { themes: ranked, week: new Date().toLocaleDateString('en-GB'), total_feedback: feedback.length } }];
